VALUES
  ('disabled-6f0ba476-moex-00431', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', 'X2年1月1日甲公司以$981,190購入乙公司發行之公司債，面額$1,000,000 ，票面利率4%，每年6 月30 日及12 月31 日付息，X3 年12 月31 日到 期，有效利率 5%，甲公司將該債券投資分類為透過其他綜合損益按公允 價值衡量之債券投資。X2 年 12 月 31 日甲公司持有之乙公司公司債帳面 金額為$990,363、公允價值為$985,363，若甲公司於 X3 年 3 月 31 日以 $981,743 加計應收利息出售，另支付手續費$2,000，則甲公司 X3 年認列 處分債券投資損益為何？', '["處分損失$2,000", "處分損失$5,620", "處分損失$11,000", "處分損失$13,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00432', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於 X2 年底以$100,000（含交易成本）買入乙公司發行之三年期公 司債，面額$100,000，票面利率5%，每年12 月31 日付息一次，分類為 按攤銷後成本衡量之債券投資。有關該公司債的預期信用損失估計如下： 12個月內預期信用損失 存續期間預期信用損失 X2年底 $1,000 $1,800 X3年底 $5,000 $10,500 X4年底 $25,000 $25,000 若X3年底該債券的信用風險已顯著增加，X4年底該債券已自活絡市場中 消失，已達減損的地步。則甲公司於 X2 年底、X3 年底、X4 年底分別應 認列之減損損失金額為何？', '["$1,000、$5,000、$25,000", "$1,800、$10,500、$25,000", "$1,000、$9,500、$14,500", "$1,800、$8,700、$14,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00433', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X2 年有關退休金資料如下：期初計畫資產公允價值$600,000，期 初確定給付義務現值$750,000，X2年當期服務成本為$112,500，因退休計 畫精算假設變動產生精算損失$95,000，X2 年底提撥退休基金$124,000， 並支付退休金$107,000。已知折現率為 5%，計畫資產實際報酬為$68,000 ，則甲公司X2年12月31日資產負債表應報導之退休金負債為何？', '["$53,000", "$70,000", "$108,000", "$203,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00434', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', 'X1 年 1 月 1 日甲公司為進行新冠病毒疫苗之研發向衛生福利部申請補助 款，計獲得補助款 $6,000,000。該計畫總研發成本，自X1 年1月1 日起', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00435', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '年內平均發生。疫苗開發完成後，受補助廠商可完全取得開發產品之專 利權，甲公司預計於 X3 年度完成疫苗開發計畫。甲公司於 X2 年 1 月 1 日疫苗第一階段測試失敗而中止研發計畫，違反衛生福利部補助條件，被 要求退還部分補助款$3,000,000。試問上述交易事項對甲公司X2年度本期 淨利之淨影響為何？（不考慮所得稅）', '["增加$500,000", "不受影響", "增加$1,000,000", "減少$1,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00436', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於 X2 年 1 月 1 日購入一機器設備，成本$546,000，估計耐用年限 6年，殘值$21,000，採年數合計法提列折舊，以成本模式衡量。X4年底該 機器使用方式發生不利之重大變動，經減損測試，估計該機器未來現金流 量現值為$150,000，公允價值為$160,000，處分成本為$2,000，則X4年底 甲公司應認列之減損損失金額為多少？', '["$0", "$6,000", "$13,000", "$21,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00437', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X1年1月1日以$800,000購買一辦公設備，估計耐用年限8年 ，無殘值，該設備認列後之衡量採成本模式並以直線法提列折舊。此外， 基於政府之安全法規，該設備出廠時須進行重大安檢且每使用5年亦須進 行一次重大安檢。X3 年中法規修改為須每 3 年進行一次安全檢查，甲公 司於X3年12月31日實際發生之檢查成本為$50,000，該成本符合認列條 件。甲公司於X1年1月1 日購買設備時無客觀資料可個別辨認內含之重 大檢查成本，但經專家協助評估該檢查成本之金額為$30,000。前述交易對 X3年度甲公司稅前淨利之影響為何？', '["減少$12,000", "減少$114,250", "減少$118,750", "減少$131,250"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00438', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於 X2 年初購入一棟供出租用的辦公大樓，成本$40,000,000，估計 耐用年限為 40 年，無殘值，採直線法提列折舊。該辦公大樓符合分類為 投資性不動產，公司對投資性不動產採用公允價值模式衡量。X7 年初因 辦公大樓電梯頻頻故障，公司決定更換，換裝新電梯之成本共計$3,600,000 。X7年初及X7年底該辦公大樓公允價值分別為$37,800,000及$39,000,000 ，若舊電梯被重置時之公允價值為$1,800,000，則該投資性不動產之重置 及評價對X7年度損益之淨影響為何？', '["產生損失$600,000", "產生損失$2,400,000", "產生利益$1,200,000", "產生利益$2,200,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00439', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲農場於X2年6 月30日購入50棵蘋果樹苗，種植在農場內，擬未來產 出蘋果出售。甲農場預期於 X4 年初該批果樹可達成熟階段而開始收成蘋 果，此樹種正常收成年限（耐用年限）為50年，且每年均可正常收成，估 計殘值為$0。每棵蘋果樹苗之購買價格為$80,000，另外發生運送費用 $13,000，交易成本$8,000。X2年度種植期間甲農場投入種植成本$232,500 ，X2 年底果樹之公允價值減出售成本為$4,200,000。X3 年度投入種植成 本$379,500，X3年底果樹之公允價值減出售成本為$5,800,000。X4年度共 採收蘋果 8,000 公斤，發生採收成本$150,000，每公斤蘋果之公允價值減 出售成本為$185，後續以每公斤$200之價格售出，並支付運費及相關出售 成本每公斤$5。X4 年度投入種植成本共$180,000，X4 年底果樹之公允價 值減出售成本為$4,550,000。試問前述交易對甲農場X4年度稅前淨利之影 響數為：', '["$1,137,340", "$1,317,340", "$1,330,000", "$1,357,340"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00440', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X2年1 月1 日訂有顧客忠誠計畫，約定顧客每消費$1,000 可獲贈 1點獎勵積點，每1點可用於未來消費時折抵$100。X2年1月31日顧客 消費$30,000,000，獲得24,000 點。甲公司預估顧客將兌換18,000 點，X2 年實際兌換12,000點，則甲公司X2年應認列銷貨收入為何？', '["$28,325,581", "$29,272,727", "$29,302,326", "$29,441,860"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
